	Attempting to mmap() thousands of files caused the system to
	reboot or panic (can't tell which, the system is many miles away,
	but dmesg shows no saved data).  It freaked both times I tried it.

	The same program, run under Solaris, eventually quit with an
	ENOMEM error.

Fix: 

Don't mmap trillions of files.  :-)  Probably not a good sol'n.
How-To-Repeat: 
Program:

#include        <stdio.h>
#include        <sys/types.h>
#include        <sys/stat.h>
#include        <sys/mman.h>
#include        <fcntl.h>

#define         MAX             1048576

caddr_t array[MAX];

int main()
{
        int i = 0;
        int fd;
        char filename[2048];
        struct stat s;
        caddr_t this;

        while (i < MAX) {
                gets(filename);
                if ((fd = open(filename, O_RDONLY, 0)) < 0) {
                        perror(filename);
                        sleep(1);
                } else {
                        if (fstat(fd, &s) < 0) {
                                perror("fstat");
                                sleep(1);
                        } else {
                                this = mmap((caddr_t) 0, s.st_size, PROT_READ,
                                        MAP_PRIVATE, fd, (off_t) 0);
                                if ((int) this == -1) {
                                        perror("mmap");
                                        sleep(1);
                                } else {
                                        array[i++] = this;
                                }
                        }
                        close(fd);
                }
                if (! (i % 512)) {
                        fprintf(stderr, "[%d] .. ", i);
                }
        }
}

